import React from 'react';

// Very small, dependency-free chart components using SVG.
export function BarChart({ title = '', data = [], xLabel = '', yLabel = '', maxHeight = 200 }) {
	const max = Math.max(...data.map(d => d.value || 0), 1);
	return (
		<div>
			{title && <div className="text-sm font-medium mb-2">{title}</div>}
			<svg width="100%" height={maxHeight} viewBox={`0 0 ${data.length * 40} ${maxHeight}`} preserveAspectRatio="xMidYMid meet">
				{data.map((d, i) => {
					const h = (d.value / max) * (maxHeight - 40);
					const x = i * 40 + 10;
					const y = maxHeight - h - 20;
					return (
						<g key={i}>
							<rect x={x} y={y} width={20} height={h} fill={d.color || '#3b82f6'} />
							<text x={x + 10} y={maxHeight - 5} fontSize="10" textAnchor="middle" fill="#374151">{d.label}</text>
						</g>
					);
				})}
			</svg>
		</div>
	);
}

export function LineChart({ title = '', data = [], xLabel = '', yLabel = '', maxHeight = 200 }) {
	const max = Math.max(...data.map(d => d.value || 0), 1);
	const width = Math.max(300, data.length * 40);
	const points = data.map((d, i) => `${i * (width / Math.max(1, data.length - 1))},${maxHeight - ((d.value / max) * (maxHeight - 40)) - 20}`).join(' ');
	return (
		<div>
			{title && <div className="text-sm font-medium mb-2">{title}</div>}
			<svg width="100%" height={maxHeight} viewBox={`0 0 ${width} ${maxHeight}`} preserveAspectRatio="xMidYMid meet">
				<polyline fill="none" stroke="#3b82f6" strokeWidth="2" points={points} />
				{data.map((d, i) => {
					const x = i * (width / Math.max(1, data.length - 1));
					const y = maxHeight - ((d.value / max) * (maxHeight - 40)) - 20;
					return <circle key={i} cx={x} cy={y} r={3} fill={d.color || '#3b82f6'} />;
				})}
			</svg>
		</div>
	);
}

export function PieChart({ title = '', data = [], maxHeight = 200 }) {
	const total = data.reduce((s, d) => s + (d.value || 0), 0) || 1;
	let angle = -Math.PI / 2;
	const cx = 100, cy = 100, r = 80;
	const slices = data.map((d, i) => {
		const frac = (d.value || 0) / total;
		const next = angle + frac * Math.PI * 2;
		const x1 = cx + r * Math.cos(angle);
		const y1 = cy + r * Math.sin(angle);
		const x2 = cx + r * Math.cos(next);
		const y2 = cy + r * Math.sin(next);
		const large = frac > 0.5 ? 1 : 0;
		const path = `M ${cx} ${cy} L ${x1} ${y1} A ${r} ${r} 0 ${large} 1 ${x2} ${y2} Z`;
		angle = next;
		return { path, color: d.color || ['#3b82f6','#ef4444','#10b981','#f59e0b','#8b5cf6'][i%5], label: d.label, value: d.value };
	});

	return (
		<div className="flex items-start gap-4">
			<div>
				{title && <div className="text-sm font-medium mb-2">{title}</div>}
				<svg width={200} height={200} viewBox="0 0 200 200">
					{slices.map((s, i) => <path key={i} d={s.path} fill={s.color} stroke="#fff" />)}
				</svg>
			</div>
			<div className="text-sm">
				{slices.map((s, i) => (
					<div key={i} className="flex items-center gap-2 mb-1">
						<span style={{width:12,height:12,background:s.color,display:'inline-block'}} />
						<div>{s.label}: <span className="font-semibold">{s.value}</span></div>
					</div>
				))}
			</div>
		</div>
	);
}

export default { BarChart, LineChart, PieChart };
